# locustfile.py — load test an agent HTTP endpoint
from locust import HttpUser, task, between


class AgentUser(HttpUser):
    # Think time between requests: 1–3 seconds (simulates human reading time)
    wait_time = between(1, 3)

    @task(3)
    def ask_simple_question(self):
        self.client.post(
            "/v1/agent/turn",
            json={"message": "Summarize clause 3 of the contract."},
            timeout=60,
        )

    @task(1)
    def ask_complex_question(self):
        self.client.post(
            "/v1/agent/turn",
            json={"message": "Compare risk provisions across all attached contracts."},
            timeout=120,
        )

# Run:
# locust -f locustfile.py --headless -u 20 -r 2 --run-time 120s \
#        --host http://localhost:8080
